<?php\n\nclass Chat {\n    private $db;\n    private $table = 'messages';\n\n    public function __construct($db) {\n        $this->db = $db;\n    }\n\n    // Send message\n    public function sendMessage($sender_id, $receiver_id, $message) {\n        $query = 'INSERT INTO ' . $this->table . '\n                  (sender_id, receiver_id, message, is_read, created_at)\n                  VALUES\n                  (:sender_id, :receiver_id, :message, 0, NOW())';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':sender_id', $sender_id);\n        $stmt->bindParam(':receiver_id', $receiver_id);\n        $stmt->bindParam(':message', $message);\n\n        return $stmt->execute();\n    }\n\n    // Get conversation between two users\n    public function getConversation($user_id1, $user_id2, $limit = 50) {\n        $query = 'SELECT m.id, m.sender_id, m.receiver_id, m.message, m.is_read, m.created_at,\n                         u.username, u.full_name, u.profile_pic\n                  FROM ' . $this->table . ' m\n                  JOIN users u ON m.sender_id = u.id\n                  WHERE (m.sender_id = :user_id1 AND m.receiver_id = :user_id2)\n                  OR (m.sender_id = :user_id2 AND m.receiver_id = :user_id1)\n                  ORDER BY m.created_at DESC\n                  LIMIT :limit';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':user_id1', $user_id1);\n        $stmt->bindParam(':user_id2', $user_id2);\n        $stmt->bindParam(':limit', $limit, PDO::PARAM_INT);\n        $stmt->execute();\n\n        $messages = $stmt->fetchAll(PDO::FETCH_ASSOC);\n        return array_reverse($messages); // Return in ascending order\n    }\n\n    // Get user conversations (latest messages with each friend)\n    public function getUserConversations($user_id) {\n        $query = 'SELECT DISTINCT\n                    CASE\n                        WHEN m.sender_id = :user_id THEN m.receiver_id\n                        ELSE m.sender_id\n                    END as friend_id,\n                    u.username, u.full_name, u.profile_pic,\n                    m.message, m.created_at, m.is_read, m.sender_id\n                  FROM ' . $this->table . ' m\n                  JOIN users u ON u.id = CASE\n                      WHEN m.sender_id = :user_id THEN m.receiver_id\n                      ELSE m.sender_id\n                  END\n                  WHERE m.sender_id = :user_id OR m.receiver_id = :user_id\n                  ORDER BY m.created_at DESC';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':user_id', $user_id);\n        $stmt->execute();\n\n        return $stmt->fetchAll(PDO::FETCH_ASSOC);\n    }\n\n    // Mark message as read\n    public function markAsRead($message_id, $receiver_id) {\n        $query = 'UPDATE ' . $this->table . '\n                  SET is_read = 1\n                  WHERE id = :id AND receiver_id = :receiver_id';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':id', $message_id);\n        $stmt->bindParam(':receiver_id', $receiver_id);\n\n        return $stmt->execute();\n    }\n\n    // Mark all messages as read\n    public function markAllAsRead($receiver_id, $sender_id) {\n        $query = 'UPDATE ' . $this->table . '\n                  SET is_read = 1\n                  WHERE receiver_id = :receiver_id AND sender_id = :sender_id AND is_read = 0';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':receiver_id', $receiver_id);\n        $stmt->bindParam(':sender_id', $sender_id);\n\n        return $stmt->execute();\n    }\n\n    // Get unread count\n    public function getUnreadCount($user_id) {\n        $query = 'SELECT COUNT(*) as count FROM ' . $this->table . '\n                  WHERE receiver_id = :user_id AND is_read = 0';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':user_id', $user_id);\n        $stmt->execute();\n\n        $result = $stmt->fetch(PDO::FETCH_ASSOC);\n        return $result['count'];\n    }\n\n    // Delete message\n    public function deleteMessage($message_id, $user_id) {\n        $query = 'DELETE FROM ' . $this->table . '\n                  WHERE id = :id AND sender_id = :user_id';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':id', $message_id);\n        $stmt->bindParam(':user_id', $user_id);\n\n        return $stmt->execute();\n    }\n\n    // Search messages\n    public function searchMessages($user_id, $search_term) {\n        $query = 'SELECT m.id, m.sender_id, m.receiver_id, m.message, m.created_at,\n                         u.username, u.full_name\n                  FROM ' . $this->table . ' m\n                  JOIN users u ON m.sender_id = u.id\n                  WHERE (m.sender_id = :user_id OR m.receiver_id = :user_id)\n                  AND m.message LIKE :search_term\n                  ORDER BY m.created_at DESC';\n\n        $stmt = $this->db->prepare($query);\n        $stmt->bindParam(':user_id', $user_id);\n        $stmt->bindParam(':search_term', '%' . $search_term . '%');\n        $stmt->execute();\n\n        return $stmt->fetchAll(PDO::FETCH_ASSOC);\n    }\n}\n\n?>"